node -e "
const { sortVersions } = require('./src/core/versions.js');

// Basic numeric ordering
console.assert(JSON.stringify(sortVersions(['1.10.0','1.2.0'])) === JSON.stringify(['1.2.0','1.10.0']), 'numeric major.minor');

// Pre-release < release
console.assert(JSON.stringify(sortVersions(['1.0.0','1.0.0-rc.1'])) === JSON.stringify(['1.0.0-rc.1','1.0.0']), 'pre-release < release');

// Pre-release field ordering: numeric
console.assert(JSON.stringify(sortVersions(['1.0.0-alpha.10','1.0.0-alpha.2'])) === JSON.stringify(['1.0.0-alpha.2','1.0.0-alpha.10']), 'pre-release numeric fields');

// Pre-release field ordering: lexical
console.assert(JSON.stringify(sortVersions(['1.0.0-rc','1.0.0-alpha'])) === JSON.stringify(['1.0.0-alpha','1.0.0-rc']), 'pre-release lexical');

// More fields = higher precedence
console.assert(JSON.stringify(sortVersions(['1.0.0-alpha.1','1.0.0-alpha'])) === JSON.stringify(['1.0.0-alpha','1.0.0-alpha.1']), 'more fields higher');

// Build metadata ignored
console.assert(JSON.stringify(sortVersions(['1.0.0+build.9','1.0.0+build.5'])) === JSON.stringify(['1.0.0+build.9','1.0.0+build.5']), 'build metadata equal');

// Does not mutate
const arr = ['1.2.0','1.10.0'];
sortVersions(arr);
console.assert(JSON.stringify(arr) === JSON.stringify(['1.2.0','1.10.0']), 'no mutation');

console.log('All assertions passed');
